fun main() {
    println("Forward range:")
    for (i in 1..5) print("$i ")
    println()

    println("With step:")
    for (i in 1..10 step 2) print("$i ")
    println()

    println("Downward:")
    for (i in 5 downTo 1) print("$i ")
    println()

    val x = 7
    println("$x in 1..10: ${x in 1..10}")
    println("'c' in 'a'..'z': ${'c' in 'a'..'z'}")
}
